diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 550f095b26ba..1becb7cb6a9b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1275,6 +1275,7 @@ Instruction *InstCombinerImpl::visitShl(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   if (Value *V = simplifyLShrInst(I.getOperand(0), I.getOperand(1), I.isExact(),
                                   SQ.getWithInstruction(&I)))
@@ -1382,7 +1383,7 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
     if (match(Op0, m_Shl(m_Value(X), m_APInt(C1))) && C1->ult(BitWidth)) {
       if (C1->ult(ShAmtC)) {
         unsigned ShlAmtC = C1->getZExtValue();
-        Constant *ShiftDiff = ConstantInt::get(Ty, ShAmtC - ShlAmtC);
+        Constant *ShiftDiff = ConstantInt::get(Ty, ShAmtC - ShAmtC);
         if (cast<BinaryOperator>(Op0)->hasNoUnsignedWrap()) {
           // (X <<nuw C1) >>u C --> X >>u (C - C1)
           auto *NewLShr = BinaryOperator::CreateLShr(X, ShiftDiff);
@@ -1433,6 +1434,50 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
       return BinaryOperator::CreateAnd(NewAdd, Mask);
     }

+    // lshr (and X, C1), C --> and (lshr X, C), (C1 >> C)
+    if (match(Op0, m_And(m_Value(X), m_APInt(C1)))) {
+      APInt NewC = C1->lshr(ShAmtC);
+      if (NewC.isZero())
+        return replaceInstUsesWith(I, ConstantInt::getNullValue(Ty));
+      APInt Mask = APInt::getLowBitsSet(BitWidth, BitWidth - ShAmtC);
+      if ((NewC & Mask) == Mask)
+        return BinaryOperator::CreateLShr(X, Op1);
+      if (Op0->hasOneUse()) {
+        Value *NewLShr = Builder.CreateLShr(X, Op1);
+        return BinaryOperator::CreateAnd(NewLShr, ConstantInt::get(Ty, NewC));
+      }
+    }
+
+    // add (lshr X, C), (and X, Mask) -> sub X, mul (lshr X, C), Mask
+    // where Mask = (1 << C) - 1.
+    // This transform is valid with nuw/nsw flags because the result is
+    // mathematically equivalent and fits in the type.
+    if (I.hasOneUse()) {
+      if (auto *AddI = dyn_cast<BinaryOperator>(*I.user_begin())) {
+        if (AddI->getOpcode() == Instruction::Add &&
+            AddI->hasNoUnsignedWrap() && AddI->hasNoSignedWrap()) {
+          Value *OtherOp = AddI->getOperand(0) == &I ? AddI->getOperand(1)
+                                                     : AddI->getOperand(0);
+          const APInt *MaskC;
+          if (match(OtherOp, m_c_And(m_Specific(Op0), m_APInt(MaskC)))) {
+            APInt ExpectedMask = APInt::getLowBitsSet(BitWidth, ShAmtC);
+            if (*MaskC == ExpectedMask) {
+              Value *Mul = Builder.CreateMul(&I, ConstantInt::get(Ty, *MaskC),
+                                             "", /*HasNUW=*/true,
+                                             /*HasNSW=*/true);
+              Value *Sub = Builder.CreateSub(Op0, Mul, "", /*HasNUW=*/true,
+                                             /*HasNSW=*/true);
+              replaceInstUsesWith(*AddI, Sub);
+              eraseInstFromFunction(*AddI);
+              if (OtherOp->use_empty())
+                eraseInstFromFunction(*cast<Instruction>(OtherOp));
+              return nullptr;
+            }
+          }
+        }
+      }
+    }
+
     if (match(Op0, m_OneUse(m_ZExt(m_Value(X)))) &&
         (!Ty->isIntegerTy() || shouldChangeType(Ty, X->getType()))) {
       assert(ShAmtC < X->getType()->getScalarSizeInBits() &&
@@ -1638,6 +1683,7 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *
 InstCombinerImpl::foldVariableSignZeroExtensionOfVariableHighBitExtract(
     BinaryOperator &OldAShr) {
